from dataclasses import dataclass

@dataclass
class Criterion:
    name: str
    metric_fn: callable
    threshold: float
    is_blocking: bool

def evaluate_all_criteria(
    results: dict,
    criteria: list[Criterion],
) -> dict:
    """
    Evaluate a system against all success criteria.
    Returns pass/fail per criterion and overall deploy decision.
    """
    outcomes = {}
    can_deploy = True

    for c in criteria:
        score = c.metric_fn(results)
        passed = score >= c.threshold
        outcomes[c.name] = {"score": score, "threshold": c.threshold, "passed": passed}
        if not passed and c.is_blocking:
            can_deploy = False

    return {"can_deploy": can_deploy, "criteria": outcomes}
